'use client'

import React from 'react'
import Link from 'next/link'
import Image from 'next/image'
import { usePathname } from 'next/navigation'
import { cn } from '@/lib/utils'
import { SignedIn, SignedOut, SignInButton, SignUpButton, UserButton } from '@clerk/nextjs'

const navItems = [
    { label: "Library", href: "/" },
    { label: "Add New", href: "/books/new"}
]

const Navbar = () => {
    const pathName = usePathname();

  return (
    <header className='w-full fixed z-50 bg-("--bg-primary")'>
      <div className='wrapper navbar-height py-4 flex justify-between items-center'>
        <Link href="/" className="flex gap-0.5 items-center">
            <Image src="/assets/logo.png" alt="Bookified" width={42} height={26} />
            <span className='logo-text'>Bookified</span>
        </Link>

        <nav className='w-fit flex gap-7.5 items-center'>
            {navItems.map(({ label, href }) => {
                const isActive = pathName === href || (href !== '/' && pathName.startsWith(href));

                return (
                    <Link href={href} key={label} className={cn('nav-link-base', isActive ? 'nav-link-active' : 'text-black hover:opacity-70')}>
                        {label}
                    </Link>
                )
            })}
        </nav>
            <div className="flex items-center gap-4">
              <SignedOut>
                <SignInButton>
                  <button className='nav-link-base'>Sign in</button>
                </SignInButton>
                <SignUpButton>
                  <button className='nav-link-base'>Sign up</button>
                </SignUpButton>
              </SignedOut>
              <SignedIn>
                <UserButton />
              </SignedIn>
            </div>
      </div>
    </header>
  )
}

export default Navbar
